const { app } = require('@azure/functions');
const { CosmosClient } = require('@azure/cosmos');

const cosmosClient = new CosmosClient(process.env.COSMOS_CONNECTION_STRING);
const database = cosmosClient.database(process.env.COSMOS_DATABASE);
const container = database.container(process.env.COSMOS_CONTAINER);

const BATCH_SIZE = 100;
const MAX_PARALLEL_OPERATIONS = 10;

async function processBatch(items) {
    const results = [];
    for (const item of items) {
        try {
            const processed = {
                ...item,
                processed: true,
                processedAt: new Date().toISOString(),
                transformedData: transformData(item),
                aggregatedMetrics: calculateMetrics(item)
            };
            results.push(processed);
        } catch (error) {
            results.push({
                ...item,
                error: error.message,
                processedAt: new Date().toISOString(),
                processed: false
            });
        }
    }
    return results;
}

function transformData(item) {
    if (!item.data) return null;
    
    return {
        normalized: normalizeValues(item.data),
        enriched: enrichData(item.data),
        validated: validateData(item.data)
    };
}

function normalizeValues(data) {
    const normalized = {};
    for (const key in data) {
        if (typeof data[key] === 'string') {
            normalized[key] = data[key].trim().toLowerCase();
        } else if (typeof data[key] === 'number') {
            normalized[key] = parseFloat(data[key].toFixed(2));
        } else {
            normalized[key] = data[key];
        }
    }
    return normalized;
}

function enrichData(data) {
    return {
        ...data,
        enrichedAt: new Date().toISOString(),
        category: categorizeData(data),
        priority: calculatePriority(data),
        tags: generateTags(data)
    };
}

function validateData(data) {
    return {
        isValid: checkValidity(data),
        validationErrors: getValidationErrors(data),
        completeness: calculateCompleteness(data)
    };
}

function categorizeData(data) {
    if (data.value > 1000) return 'high';
    if (data.value > 100) return 'medium';
    return 'low';
}

function calculatePriority(data) {
    let priority = 0;
    if (data.urgent) priority += 10;
    if (data.value) priority += Math.min(data.value / 100, 5);
    return Math.min(priority, 10);
}

function generateTags(data) {
    const tags = [];
    if (data.type) tags.push(data.type);
    if (data.category) tags.push(data.category);
    if (data.region) tags.push(data.region);
    return tags;
}

function checkValidity(data) {
    return data && typeof data === 'object' && Object.keys(data).length > 0;
}

function getValidationErrors(data) {
    const errors = [];
    if (!data.id) errors.push('Missing id');
    if (!data.timestamp) errors.push('Missing timestamp');
    if (data.value !== undefined && isNaN(data.value)) errors.push('Invalid value');
    return errors;
}

function calculateCompleteness(data) {
    const requiredFields = ['id', 'timestamp', 'value', 'type'];
    const presentFields = requiredFields.filter(field => data[field] !== undefined);
    return (presentFields.length / requiredFields.length) * 100;
}

function calculateMetrics(item) {
    return {
        totalRecords: 1,
        averageValue: item.value || 0,
        maxValue: item.value || 0,
        minValue: item.value || 0,
        timestamp: new Date().toISOString()
    };
}

async function updateProcessedItems(items) {
    const operations = items.map(item => ({
        operationType: 'Upsert',
        resourceBody: item
    }));

    const chunks = [];
    for (let i = 0; i < operations.length; i += BATCH_SIZE) {
        chunks.push(operations.slice(i, i + BATCH_SIZE));
    }

    const results = [];
    for (const chunk of chunks) {
        try {
            const response = await container.items.bulk(chunk);
            results.push(...response);
        } catch (error) {
            for (const op of chunk) {
                try {
                    await container.items.upsert(op.resourceBody);
                    results.push({ statusCode: 200 });
                } catch (err) {
                    results.push({ statusCode: 500, error: err.message });
                }
            }
        }
    }

    return results;
}

async function queryAllItems(continuationToken = null) {
    const querySpec = {
        query: 'SELECT * FROM c WHERE c.processed != true OR NOT IS_DEFINED(c.processed)',
        parameters: []
    };

    const options = {
        maxItemCount: BATCH_SIZE
    };

    if (continuationToken) {
        options.continuationToken = continuationToken;
    }

    const { resources, continuationToken: nextToken } = await container.items
        .query(querySpec, options)
        .fetchNext();

    return { items: resources, continuationToken: nextToken };
}

async function processInParallel(items) {
    const chunks = [];
    for (let i = 0; i < items.length; i += BATCH_SIZE) {
        chunks.push(items.slice(i, i + BATCH_SIZE));
    }

    const results = [];
    for (let i = 0; i < chunks.length; i += MAX_PARALLEL_OPERATIONS) {
        const parallelChunks = chunks.slice(i, i + MAX_PARALLEL_OPERATIONS);
        const parallelResults = await Promise.all(
            parallelChunks.map(chunk => processBatch(chunk))
        );
        results.push(...parallelResults.flat());
    }

    return results;
}

app.timer('batchDataProcessor', {
    schedule: '0 */5 * * * *',
    runOnStartup: false,
    handler: async (myTimer, context) => {
        const startTime = Date.now();
        let totalProcessed = 0;
        let totalErrors = 0;
        let continuationToken = null;

        context.log('Starting batch data processing...');

        try {
            do {
                const { items, continuationToken: nextToken } = await queryAllItems(continuationToken);
                continuationToken = nextToken;

                if (items.length === 0) {
                    context.log('No more items to process');
                    break;
                }

                context.log(`Processing batch of ${items.length} items...`);

                const processedItems = await processInParallel(items);
                const updateResults = await updateProcessedItems(processedItems);

                const successCount = updateResults.filter(r => r.statusCode >= 200 && r.statusCode < 300).length;
                const errorCount = updateResults.length - successCount;

                totalProcessed += successCount;
                totalErrors += errorCount;

                context.log(`Batch complete: ${successCount} successful, ${errorCount} errors`);

                const elapsedTime = (Date.now() - startTime) / 1000;
                if (elapsedTime > 540) {
                    context.log('Approaching timeout limit, stopping processing');
                    break;
                }

            } while (continuationToken);

            const totalTime = (Date.now() - startTime) / 1000;

            context.log(`Batch processing complete: ${totalProcessed} items processed, ${totalErrors} errors, ${totalTime.toFixed(2)}s elapsed`);

            return {
                status: 'completed',
                totalProcessed,
                totalErrors,
                elapsedTime: totalTime
            };

        } catch (error) {
            context.log.error('Error during batch processing:', error);
            throw error;
        }
    }
});

